code.Java:
public class Main {
    public static void main(String[] args) {
        java.util.Scanner scanner = new java.util.Scanner(System.in);
        int number = scanner.nextInt();
        scanner.close();

        if (number >= 10 && number <= 20) {
            System.out.println("In Range");
        } else {
            System.out.println("Out of Range");
        }
    }
}

